sections.example:
const nums = [3, 1, 4, 1, 5];
nums.sort((a, b) => a - b);  // ascending: [1, 1, 3, 4, 5]
nums.sort((a, b) => b - a);  // descending: [5, 4, 3, 1, 1]

const words = ["banana", "apple", "cherry"];
words.sort(); // alphabetical: ["apple", "banana", "cherry"]

