sections.example:
const intervals = [[3, 5], [1, 3], [2, 8]];
intervals.sort((a, b) => a[0] - b[0]);
// [[1,3], [2,8], [3,5]] — sorted by start time

const people = [{name: "Bob", age: 25}, {name: "Ann", age: 30}];
people.sort((a, b) => a.age - b.age);

