sections.example:
const bad = [10, 9, 80, 3];
bad.sort();  // [10, 3, 80, 9] — WRONG! String sort

const good = [10, 9, 80, 3];
good.sort((a, b) => a - b); // [3, 9, 10, 80] — correct

